"""Parse raw supply chain documents and reconstruct batch flows.

Outputs:
  work/sold_composition.csv : per (day, store, product) which producer's units were sold
  work/delivery_check.txt   : validation of TOTAL_DELIVERED_UNITS
"""
import os, re, json, csv
from collections import defaultdict, deque

BASE = '/app'

# ---------- 1. Parse store orders ----------
# orders[(day, store)] = {product: qty}
orders = defaultdict(dict)
for fn in os.listdir(f'{BASE}/raw_orders'):
    m = re.match(r'day_(\d+)_(S_\d+)_(.*)\.(txt|csv|json)$', fn)
    day, store, fmt = int(m.group(1)), m.group(2), m.group(3)
    path = f'{BASE}/raw_orders/{fn}'
    if fmt == 'api-json':
        d = json.load(open(path))
        assert d['store_id'] == store and int(d['date'].split('_')[1]) == day
        for it in d['items']:
            orders[(day, store)][it['prod_id']] = int(it['qty'])
    elif fmt == 'table-csv':
        for row in csv.DictReader(open(path), delimiter=';'):
            orders[(day, store)][row['PRODUCT']] = int(row['QUANTITY'])
    elif fmt == 'key-value':
        for line in open(path):
            mm = re.search(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)', line)
            if mm:
                orders[(day, store)][mm.group(1)] = int(mm.group(2))
    elif fmt == 'text-template':
        for line in open(path):
            mm = re.search(r'deliver (\d+) units of product (P_\d+)', line)
            if mm:
                orders[(day, store)][mm.group(2)] = int(mm.group(1))
    else:
        raise ValueError(fmt)

# ---------- 2. Parse supplier receipts ----------
# supply[(day, supplier)] = {product: qty}
supply = defaultdict(dict)
for fn in os.listdir(f'{BASE}/raw_supplier_receipts'):
    m = re.match(r'day_(\d+)_(PR_\d+)_(.*)\.(txt|csv|json)$', fn)
    day, sup, fmt = int(m.group(1)), m.group(2), m.group(3)
    path = f'{BASE}/raw_supplier_receipts/{fn}'
    if fmt == 'api-json':
        d = json.load(open(path))
        assert d['supplier_id'] == sup
        for it in d['items']:
            supply[(day, sup)][it['prod_id']] = int(it['delivered_qty'])
    elif fmt == 'table-csv':
        for row in csv.DictReader(open(path), delimiter=';'):
            supply[(day, sup)][row['PRODUCT']] = int(row['DELIVERED_QTY'])
    elif fmt == 'key-value':
        for line in open(path):
            mm = re.search(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)', line)
            if mm:
                supply[(day, sup)][mm.group(1)] = int(mm.group(2))
    elif fmt == 'text-template':
        for line in open(path):
            mm = re.search(r'delivered (\d+) units of product (P_\d+)', line)
            if mm:
                supply[(day, sup)][mm.group(2)] = int(mm.group(1))
    else:
        raise ValueError(fmt)

# ---------- 3. Parse wholesaler receipts (supplier acceptance order) ----------
# sup_order[day] = [supplier ids sorted by seq]
sup_seq = defaultdict(list)
for fn in os.listdir(f'{BASE}/raw_wholesaler_receipts'):
    txt = open(f'{BASE}/raw_wholesaler_receipts/{fn}').read()
    day = int(re.search(r'DAY: (\d+)', txt).group(1))
    sup = re.search(r'SUPPLIER_ID: (PR_\d+)', txt).group(1)
    seq = int(re.search(r'DAILY_SEQUENCE_NO: (\d+)', txt).group(1))
    sup_seq[day].append((seq, sup))
sup_order = {d: [s for _, s in sorted(v)] for d, v in sup_seq.items()}

# ---------- 4. Parse wholesaler->store receipts ----------
store_seq = defaultdict(list)
store_total = {}
for fn in os.listdir(f'{BASE}/raw_wholesaler_store_receipts'):
    txt = open(f'{BASE}/raw_wholesaler_store_receipts/{fn}').read()
    day = int(re.search(r'DAY: (\d+)', txt).group(1))
    st = re.search(r'STORE_ID: (S_\d+)', txt).group(1)
    seq = int(re.search(r'DAILY_SEQUENCE_NO: (\d+)', txt).group(1))
    tot = int(re.search(r'TOTAL_DELIVERED_UNITS: (\d+)', txt).group(1))
    store_seq[day].append((seq, st))
    store_total[(day, st)] = tot
store_order = {d: [s for _, s in sorted(v)] for d, v in store_seq.items()}

DAYS = sorted(sup_order)
print('days:', DAYS[0], DAYS[-1], len(DAYS))

# ---------- 5. Simulate wholesaler FIFO ----------
# queue per product: deque of [qty, producer, supply_day]
wq = defaultdict(deque)
# deliveries[(day, store)] = {product: [(qty, producer, supply_day), ...]} in FIFO order
deliveries = defaultdict(lambda: defaultdict(list))
mismatch = 0
report = []
for day in DAYS:
    for sup in sup_order[day]:
        for prod, qty in supply.get((day, sup), {}).items():
            wq[prod].append([qty, sup, day])
    for st in store_order[day]:
        delivered_total = 0
        for prod, qty in orders.get((day, st), {}).items():
            need = qty
            q = wq[prod]
            while need > 0 and q:
                frag = q[0]
                take = min(need, frag[0])
                deliveries[(day, st)][prod].append((take, frag[1], frag[2]))
                frag[0] -= take
                need -= take
                delivered_total += take
                if frag[0] == 0:
                    q.popleft()
        expected = store_total[(day, st)]
        if delivered_total != expected:
            mismatch += 1
            report.append(f'MISMATCH day {day} {st}: sim {delivered_total} vs receipt {expected}')
print('store-day delivery mismatches:', mismatch)
with open(f'{BASE}/work/delivery_check.txt', 'w') as f:
    f.write(f'mismatches: {mismatch}\n')
    f.write('\n'.join(report[:50]))

# ---------- 6. Store-side FIFO + sales consumption ----------
import pandas as pd
sales = pd.read_csv(f'{BASE}/sales_log.csv')
sold = sales.groupby(['Day', 'Store_ID', 'Product_ID'], sort=False)['Sold_Quantity'].sum()
sold_d = sold.to_dict()

# store queues per (store, product)
sq = defaultdict(deque)
rows = []  # day, store, product, producer, supply_day, qty_sold
errors = 0
STORES = sorted({s for _, s in store_total}, key=lambda x: int(x.split('_')[1]))
PRODUCTS = [f'P_{i}' for i in range(1, 31)]
for day in DAYS:
    # sales happen first (units delivered day d sellable from d+1) -- to verify
    for st in STORES:
        for prod in PRODUCTS:
            need = sold_d.get((day, st, prod), 0)
            q = sq[(st, prod)]
            while need > 0 and q:
                frag = q[0]
                take = min(need, frag[0])
                rows.append((day, st, prod, frag[1], frag[2], take))
                frag[0] -= take
                need -= take
                if frag[0] == 0:
                    q.popleft()
            if need > 0:
                errors += 1
    # then deliveries arrive
    for st in STORES:
        dd = deliveries.get((day, st))
        if dd:
            for prod, frags in dd.items():
                for qty, producer, sday in frags:
                    sq[(st, prod)].append([qty, producer, sday])
print('store sale shortfall errors (sales-before-delivery convention):', errors)

df = pd.DataFrame(rows, columns=['Day', 'Store_ID', 'Product_ID', 'Producer', 'Supply_Day', 'Qty'])
df.to_csv(f'{BASE}/work/sold_composition.csv', index=False)
print('sold composition rows:', len(df))
print(df.head(20))

