import pandas as pd, numpy as np, pickle
D = pd.read_pickle('/app/work/D.pkl'); cal = pd.read_pickle('/app/work/cal.pkl')
sc = pd.read_csv('/app/work/sold_composition.csv')
reg = pickle.load(open('/app/work/reg_results.pkl','rb'))
resid={}; lev={}
for col in D.columns:
    base = D[col]/cal[col[1]]; l=base.median(); lev[col]=l; resid[col]=base/l-1.0
R = pd.DataFrame(resid)

flagged = {p: list(res[res<-4].index) for p,res in reg.items()}
# pooled lag regression: r_{d+k} ~ f_d  (f = flagged producer units / level), per lag k
lags = range(-3, 17)
num = {k:0.0 for k in lags}; den = {k:0.0 for k in lags}
for p, prs in flagged.items():
    sub = sc[(sc.Product_ID==p)&(sc.Producer.isin(prs))]
    g = sub.groupby(['Store_ID','Day']).Qty.sum()
    for (s,d), q in g.items():
        f = q/lev[(s,p)]
        for k in lags:
            dd = d+k
            if 1<=dd<=365:
                r = R[(s,p)].loc[dd]
                if np.isfinite(r):
                    num[k] += f*r; den[k] += f*f
print('lag profile beta_k (r_{d+k} ~ f_d):')
for k in lags:
    print(k, round(num[k]/den[k],4))
